class Solution {
    public boolean isPalindrome(String s) {
        StringBuilder cleaned = new StringBuilder();
        for (char c : s.toCharArray()) {
            if (Character.isLetterOrDigit(c)) {
                cleaned.append(Character.toLowerCase(c));
            }
        }
        String forward = cleaned.toString();
        String backward = cleaned.reverse().toString();
        return forward.equals(backward);
    }
}

class Solution {
    public boolean isPalindrome(String s) {
        int left = 0, right = s.length() - 1;
        while (left < right) {
            while (left < right && !Character.isLetterOrDigit(s.charAt(left))) left++;
            while (left < right && !Character.isLetterOrDigit(s.charAt(right))) right--;

            if (Character.toLowerCase(s.charAt(left)) != Character.toLowerCase(s.charAt(right))) {
                return false;
            }
            left++;
            right--;
        }
        return true;
    }
}

class Solution {
    public void moveZeroes(int[] nums) {
        java.util.List<Integer> nonZeros = new java.util.ArrayList<>();
        for (int num : nums) {
            if (num != 0) nonZeros.add(num);
        }
        for (int i = 0; i < nums.length; i++) {
            nums[i] = i < nonZeros.size() ? nonZeros.get(i) : 0;
        }
    }
}

class Solution {
    public void moveZeroes(int[] nums) {
        int slow = 0;
        for (int fast = 0; fast < nums.length; fast++) {
            if (nums[fast] != 0) {
                int temp = nums[slow];
                nums[slow] = nums[fast];
                nums[fast] = temp;
                slow++;
            }
        }
    }
}

class Solution {
    public int removeDuplicates(int[] nums) {
        java.util.List<Integer> unique = new java.util.ArrayList<>();
        for (int num : nums) {
            if (unique.isEmpty() || !unique.get(unique.size() - 1).equals(num)) {
                unique.add(num);
            }
        }
        for (int i = 0; i < unique.size(); i++) {
            nums[i] = unique.get(i);
        }
        return unique.size();
    }
}

